With:

{code:swift}// Detect class change and reassign terminals if needed
let oldNodeClass = node.node_class
let classChanged = oldNodeClass?.id != updates.nodeClass?.id
node.node_class = updates.nodeClass

var modifiedEdges: [EdgeV2] = []
if classChanged {
    let allOrientations = fetchAllOrientations(modelContext: modelContext)
    modifiedEdges = reassignTerminalsForNode(
        node,
        oldNodeClass: oldNodeClass,
        newNodeClass: updates.nodeClass,
        allOrientations: allOrientations,
        modelContext: modelContext
    )
    print("[TERMINAL] Class changed: reassigned \(modifiedEdges.count) edges")
}{code}

h3. Step 3: Queue Edge Updates After Node Sync

In {{updateNode()}}, after the existing node sync block (after line 196), add edge sync handling:

{code:swift}// Queue edge updates for modified edges from terminal reassignment
if !modifiedEdges.isEmpty {
    if networkState.mode == .online {
        Task {
            for edge in modifiedEdges {
                do {
                    _ = try await APIClient.shared.updateEdge(edge)
                    edge.lastSyncedAt = Date()
                    edge.needsSync = false
                } catch {
                    let op = SyncOp(target: .edge, operation: .update, edge: edge)
                    networkState.enqueue(op)
                }
            }
            try? modelContext.save()
        }
    } else {
        for edge in modifiedEdges {
            let op = SyncOp(target: .edge, operation: .update, edge: edge)
            networkState.enqueue(op)
        }
    }
}{code}

