*File*: {{eg-pz-frontend/src/sld/src/utils/terminalHelpers.js}}

Update default terminal selection to use {{side}} instead of handle_code pattern:

{code:javascript}export function getDefaultSourceTerminal(node) {
  const terminals = node?.data?.node_terminals || [];
  return terminals.find((t) => t.side === "LOAD" && !t.is_deleted);
}

export function getDefaultTargetTerminal(node) {
  const terminals = node?.data?.node_terminals || [];
  return terminals.find((t) => t.side === "LINE" && !t.is_deleted);
}{code}

