h3. Phase 2: Frontend - Update terminalHelpers.js

*File*: {{eg-pz-frontend/src/sld/src/utils/terminalHelpers.js}}

Update {{getTerminalsForNode()}} to prefer instance-level terminals with fallback to blueprint:

{code:javascript}export function getTerminalsForNode(node) {
  // Check for instance-level terminals first
  if (node?.data?.node_terminals?.length > 0) {
    return node.data.node_terminals.filter(t => !t.is_deleted);
  }

  // Fallback to class-level blueprint terminals
  const customClass = node?.data?.customClass || {};
  const orientation = customClass.node_orientation;

  if (!orientation?.orientation_terminals) {
    return [];
  }

  return orientation.orientation_terminals.filter(t => !t.is_deleted);
}{code}

*Why*: This provides backward compatibility - existing nodes without {{node_terminals}} continue to work while new nodes with instance-level terminals are supported.

----

h3. Phase 3: Frontend - Create NodeTerminal Helper Function

*File*: {{eg-pz-frontend/src/sld/src/utils/terminalHelpers.js}}

Add new function to instantiate terminals during node creation:

{code:javascript}import { v4 as uuidv4 } from 'uuid';

/**
 * Create NodeTerminal instances from a NodeClass's OrientationTerminals.
 * @param {string} nodeId - The UUID of the node being created
 * @param {Object} nodeClass - The node class with node_orientation data
 * @returns {Array} Array of NodeTerminal objects
 */
export function createNodeTerminals(nodeId, nodeClass) {
  const orientation = nodeClass?.node_orientation;
  const blueprintTerminals = orientation?.orientation_terminals || [];

  return blueprintTerminals
    .filter(t => !t.is_deleted)
    .map(blueprint => ({
      // Instance data (stored in node_terminals table)
      id: uuidv4(),
      node_id: nodeId,
      node_orientation_terminal_id: blueprint.id,
      voltage_rating: null,
      amp_rating: null,
      phase_count: null,
      is_deleted: false,
      // Blueprint reference for rendering
      handle_code: blueprint.handle_code,
      label: blueprint.label,
      side: blueprint.side,
      position: blueprint.position,
      offset_percent: blueprint.offset_percent,
      color: blueprint.color,
      show_label: blueprint.show_label,
    }));
}{code}

