      label: node.data.label,
      type: node.type,
      x: node.position.x,
      y: node.position.y,
      classId: node.data.classId,
      parentId: node.parentId || null,
      // Include terminals with UUIDs for Swift
      node_terminals: (node.data.node_terminals || []).map(t => ({
        id: t.id,
        node_orientation_terminal_id: t.node_orientation_terminal_id,
