// Pass terminals to preview
<NodeClassPreview
  iconName={selectedIconName}
  iconSvg={selectedIconSvg}
  orientation={selectedOrientationCode}
  orientationTerminals={selectedOrientation?.orientation_terminals || []}
  label={formData.name || 'New Node'}
/>{noformat}

*AssetClassEditor.jsx:*

