h3. 1. Add NodeV2 Terminal Extension

*New File:* {{eg-pz-mobile-iOS/Egalvanic PZ/Core/Models/Extensions/NodeV2+Terminals.swift}}

{code:swift}extension NodeV2 {
    /// Terminals eligible for source connections (LOAD side)
    var sourceEligibleTerminals: [NodeTerminal] {
        node_terminals.filter { !$0.is_deleted && $0.side == "LOAD" }
    }

    /// Terminals eligible for target connections (LINE side)
    var targetEligibleTerminals: [NodeTerminal] {
        node_terminals.filter { !$0.is_deleted && $0.side == "LINE" }
    }

    /// Whether this node can be an edge source
    var canBeSource: Bool { !sourceEligibleTerminals.isEmpty }

    /// Whether this node can be an edge target
    var canBeTarget: Bool { !targetEligibleTerminals.isEmpty }
}{code}

