h3. Step 3: Queue Edge Updates After Node Sync

In {{updateNode()}}, after the existing node sync block (after line 196), add edge sync handling:

{code:swift}// Queue edge updates for modified edges from terminal reassignment
if !modifiedEdges.isEmpty {
    if networkState.mode == .online {
        Task {
            for edge in modifiedEdges {
                do {
                    _ = try await APIClient.shared.updateEdge(edge)
                    edge.lastSyncedAt = Date()
                    edge.needsSync = false
                } catch {
                    let op = SyncOp(target: .edge, operation: .update, edge: edge)
                    networkState.enqueue(op)
                }
            }
            try? modelContext.save()
        }
    } else {
        for edge in modifiedEdges {
            let op = SyncOp(target: .edge, operation: .update, edge: edge)
            networkState.enqueue(op)
        }
    }
}{code}

