{code:python}def _draw_sld_link(self, c, x, y, width, height, node_info):
    # Circle (left 1/3)
    symbol_width = width / 3
    center_x = x + symbol_width / 2
    center_y = y + height / 2
    radius = min(symbol_width, height) * 0.4

    c.setStrokeColorRGB(0.23, 0.51, 0.96)  # #3b82f6
    c.setFillColorRGB(0.94, 0.96, 1.0)     # #eff6ff
    c.setLineWidth(2)
