 *6. Deleted Sessions Filter Fix*

  *File:* Views/Sessions/IRSessionView.swift

  *Bug Fix*

  Sessions with is_deleted = true were still appearing in the list.



  *Changes*

  // New computed property

  private var nonDeletedSessions: [IRSession] {

      irSessions.filter { !$0.is_deleted }

  }



  // Updated all usages:

  activeSessions → nonDeletedSessions.filter { $0.active }

  inactiveSessions → nonDeletedSessions.filter { !$0.active }

  displayedSessions → showAllSessions ? nonDeletedSessions : activeSessions

  totalPhotoCount → nonDeletedSessions.reduce(...)
